module RefModule(
        input           iCLK,
        input           iWRMLR,
        input  [7:0]    iMULHB,
        output [7:0]    oMULRG
    );reg [7:0]       obf_rMULRG = 8'h00;
    assign oMULRG = obf_rMULRG;

    always@(posedge iCLK) begin
        if(iWRMLR) begin
            obf_rMULRG <= iMULHB;
        end
        else begin
            obf_rMULRG <= obf_rMULRG;
        end
    end
endmodule
